#!/usr/bin/env node
const fs=require("fs"),path=require("path"),glob=require("glob"),BLOG_DIR=path.join(__dirname,"..","content","blog"),files=glob.sync("**/index.md",{cwd:BLOG_DIR});let modified=0,skipped=0;for(const o of files){const e=path.join(BLOG_DIR,o);let i=fs.readFileSync(e,"utf-8");if(!i.includes("LINK E CREDITI")){skipped++;continue}const n=i.split("\n"),s=[];let l=!1;for(const o of n)o.includes("LINK E CREDITI")?l=!0:l?(o.includes("{{< youtube")||o.includes("{{< youtube-short"))&&(l=!1,s.push(o)):s.push(o);fs.writeFileSync(e,s.join("\n")),modified++,console.log(`Modificato: ${o}`)}console.log("\nCompletato!"),console.log(`  - File modificati: ${modified}`),console.log(`  - File saltati (senza LINK E CREDITI): ${skipped}`);